using System.Linq;

class CosmosQuery
{
    // EF Core 9 Cosmos no longer supports sync I/O — use async throughout
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe: we preserved "Discriminator" via HasDiscriminator
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Sync ToList() throws in EF Core 9 Cosmos — must use ToListAsync()
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

